using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Non-static class — the SDK creates an instance per invocation and injects DI services
/// via the primary constructor.
/// </summary>
[McpServerToolType]
public class WeatherApiTools(HttpClient httpClient, ILogger<WeatherApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool(ReadOnly = true), Description("Get the current weather for a city.")]
    public async Task<string> GetCurrentWeather(
        [Description("City name, e.g. 'Seattle' or 'London'")] string city,
        [Description("Temperature unit: 'celsius' or 'fahrenheit' (default: celsius)")] string unit = "celsius",
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching weather for {City} in {Unit}", city, unit);

        var response = await httpClient.GetAsync(
            $"/v1/weather/current?city={Uri.EscapeDataString(city)}&unit={Uri.EscapeDataString(unit)}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(ReadOnly = true), Description("Get a multi-day weather forecast for a city.")]
    public async Task<string> GetForecast(
        [Description("City name, e.g. 'Seattle' or 'London'")] string city,
        [Description("Number of days to forecast (1-7, default: 3)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching {Days}-day forecast for {City}", days, city);

        var response = await httpClient.GetAsync(
            $"/v1/weather/forecast?city={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        // Re-serialize with indentation so the LLM can read it easily
        var doc = JsonSerializer.Deserialize<JsonElement>(json);
        return JsonSerializer.Serialize(doc, JsonOptions);
    }
}

